INSERT INTO opportunities (title, organization, type, description, deadline, start_date, end_date, application_url, requirements) VALUES
('Software Engineering Intern - Summer 2025', 'Google', 'internship', 'Join Google''s engineering team to work on products used by billions. Collaborate with experienced engineers on AI/ML, cloud computing, and distributed systems.', '2025-01-31', '2024-09-01', '2025-01-31', 'https://careers.google.com/jobs/results/?q=software%20engineering%20intern', ARRAY['BS/MS in Computer Science', 'Strong coding skills (Java/C++/Python)', 'Data structures and algorithms', 'Previous internship preferred']),
('Product Management Intern', 'Microsoft', 'internship', 'Define product strategy and drive feature development for Microsoft''s cloud and productivity products. Gain PM experience and cross-functional collaboration skills.', '2025-02-15', '2024-08-15', '2025-02-15', 'https://careers.microsoft.com/students/us/en/search-results?keywords=product%20management%20intern', ARRAY['Business/CS degree', 'Analytical and communication skills', 'Interest in technology products', 'Leadership experience']),
('Machine Learning Research Intern', 'Meta', 'internship', 'Conduct cutting-edge ML research in computer vision or NLP. Work with world-class researchers on generative AI, recommendation systems, and AR/VR.', '2025-01-15', '2024-09-01', '2025-01-15', 'https://www.metacareers.com/jobs/?q=machine%20learning%20intern', ARRAY['PhD/MS in CS or ML', 'Publication record', 'PyTorch or TensorFlow', 'Research experience in ML/AI']),
('Data Science Intern', 'Amazon', 'internship', 'Apply ML to solve business problems across retail, AWS, and advertising. Build predictive models, conduct A/B tests, and derive insights from large datasets.', '2025-02-28', '2024-10-01', '2025-02-28', 'https://www.amazon.jobs/en/search?base_query=data+science+intern', ARRAY['Statistics/CS degree', 'Python and SQL proficiency', 'ML libraries experience', 'Statistical analysis skills']),
('iOS Engineering Intern', 'Apple', 'internship', 'Develop innovative iOS features used by millions. Work with Swift and SwiftUI to create seamless user experiences for iPhone and iPad.', '2025-02-01', '2024-11-01', '2025-02-01', 'https://jobs.apple.com/en-us/search?search=software%20intern', ARRAY['Strong Swift programming', 'iOS development experience', 'iOS frameworks knowledge', 'Portfolio of iOS projects']);
INSERT INTO opportunities (title, organization, type, description, deadline, start_date, end_date, application_url, requirements) VALUES
('New Grad Software Engineer 2025', 'Google', 'job', 'Start your career at Google working on products impacting billions. Receive mentorship and work on challenging problems across Search, Ads, Cloud, YouTube.', '2025-03-31', '2024-09-01', '2025-03-31', 'https://careers.google.com/jobs/results/?q=new%20grad%20software%20engineer', ARRAY['BS/MS in Computer Science', 'Strong coding skills', 'Graduation Dec 2024 - Sep 2025', 'Problem-solving abilities']),
('Software Development Engineer - AWS', 'Amazon', 'job', 'Build and scale AWS services used by millions. Work on distributed systems, APIs, and cloud infrastructure. Own significant technical projects.', '2025-02-28', '2024-10-01', '2025-02-28', 'https://www.amazon.jobs/en/teams/amazon-web-services', ARRAY['2+ years software development', 'Java/C++/Python proficiency', 'Distributed systems experience', 'AWS knowledge preferred']),
('Frontend Engineer - React', 'Stripe', 'job', 'Build beautiful, performant UIs for Stripe''s payment platform. Work with React, TypeScript, and modern web tech to create seamless payment experiences.', '2025-01-31', '2024-11-15', '2025-01-31', 'https://stripe.com/jobs/search?q=frontend', ARRAY['3+ years frontend development', 'React and TypeScript expert', 'Strong design sensibility', 'Payment systems experience plus']),
('Machine Learning Engineer', 'OpenAI', 'job', 'Develop large-scale ML models powering ChatGPT and AI products. Work on model training, fine-tuning, and inference optimization with researchers.', '2025-02-15', '2024-12-01', '2025-02-15', 'https://openai.com/careers/search?q=machine%20learning', ARRAY['MS/PhD in CS or ML', 'Strong ML engineering', 'PyTorch or TensorFlow', 'Published research preferred']),
('DevOps Engineer - Platform', 'Uber', 'job', 'Build infrastructure powering Uber''s global platform. Work on CI/CD pipelines, container orchestration, and automation for millions of daily rides.', '2025-01-31', '2024-11-01', '2025-01-31', 'https://www.uber.com/careers/list/?query=devops', ARRAY['3+ years DevOps experience', 'Kubernetes and Docker expertise', 'AWS or GCP experience', 'Strong scripting skills']),
('Cybersecurity Analyst - New Grad', 'Palo Alto Networks', 'job', 'Protect organizations from cyber threats. Analyze security incidents, develop threat intelligence, and implement solutions with industry-leading tools.', '2025-02-28', '2024-12-01', '2025-02-28', 'https://jobs.paloaltonetworks.com/search-jobs/cybersecurity', ARRAY['BS in Cybersecurity or CS', 'Security concepts understanding', 'Certifications (Security+/CEH) preferred', 'Analytical skills']),
('Game Developer - Unity/Unreal', 'Epic Games', 'job', 'Create immersive gaming experiences with Unreal Engine. Work on gameplay systems, graphics programming, or engine development with creative teams.', '2025-02-15', '2024-12-15', '2025-02-15', 'https://www.epicgames.com/site/careers?type=game%20developer', ARRAY['3+ years game development', 'Unity or Unreal Engine expert', 'Strong C++ skills', 'Shipped game titles preferred']);
INSERT INTO opportunities (title, organization, type, description, deadline, start_date, end_date, application_url, requirements) VALUES
