('Google Cloud Innovators Hackathon', 'Google Cloud', 'hackathon', 'Build innovative solutions using GCP services. Focus on AI/ML, data analytics, cloud-native apps. Win GCP credits, mentorship, and job opportunities.', '2025-01-31', '2024-12-15', '2025-01-31', 'https://cloud.google.com/innovators/hackathon', ARRAY['Cloud platforms experience', 'Team of 2-5 members', 'Use 2+ GCP services', 'Working demo required']),
('NASA Space Apps Challenge 2025', 'NASA', 'hackathon', 'Solve space exploration challenges using NASA''s open data. Create solutions for Earth observation and scientific discovery. Win NASA recognition.', '2025-01-20', '2024-11-01', '2025-01-20', 'https://www.spaceappschallenge.org', ARRAY['Passion for space and science', 'Multidisciplinary teams encouraged', 'Use NASA open data', 'Any technology stack']);
INSERT INTO opportunities (title, organization, type, description, deadline, start_date, end_date, application_url, requirements) VALUES
