('Generation Google Scholarship', 'Google', 'scholarship', 'Supporting underrepresented groups in CS. $10,000 award for undergrad/grad students. Includes Scholars'' Retreat and potential internship consideration.', '2025-01-31', '2024-12-01', '2025-01-31', 'https://buildyourfuture.withgoogle.com/scholarships/generation-google-scholarship', ARRAY['From underrepresented group in tech', 'CS or related major', 'Strong academic performance', 'Leadership qualities']),
