('AI for Good Hackathon', 'United Nations', 'hackathon', 'Develop AI solutions for UN Sustainable Development Goals. Focus on climate, healthcare, education, poverty. Win implementation support and global recognition.', '2025-04-30', '2025-02-15', '2025-04-30', 'https://aiforgood.itu.int/event/hackathon-2025', ARRAY['AI/ML expertise', 'Social impact focus', 'Multidisciplinary teams', 'Scalable solutions']),
