INSERT INTO opportunities (title, organization, type, description, deadline, start_date, end_date, application_url, requirements) VALUES
('Gates Millennium Scholars Program', 'Bill & Melinda Gates Foundation', 'scholarship', 'Prestigious full scholarship covering tuition, fees, books, living expenses for outstanding minority students. Renewable through grad school with mentorship.', '2025-03-31', '2025-01-15', '2025-03-31', 'https://www.gmsp.org', ARRAY['African American/Hispanic/Asian/Native American', 'GPA 3.3 or higher', 'Pell Grant eligible', 'Leadership and community service']),
('Facebook Fellowship Program', 'Meta', 'scholarship', 'Supporting PhD students in CS research. Two-year fellowship covering tuition/fees plus $42,000 annual stipend. Includes paid Meta internship and mentorship.', '2025-04-15', '2025-02-01', '2025-04-15', 'https://research.facebook.com/fellowship', ARRAY['PhD student in CS or related', 'Strong research record', 'Publications preferred', 'Innovative research proposal']),
('Adobe Research Women-in-Technology', 'Adobe', 'scholarship', 'Supporting female students in CS. $10,000 award plus Adobe Research internship opportunity. Focus on graphics, AI, or creative technologies.', '2025-03-20', '2025-01-20', '2025-03-20', 'https://research.adobe.com/scholarship', ARRAY['Female student', 'CS or related major', 'Interest in graphics/AI/creativity', 'Strong academic performance']),
('NSF Graduate Research Fellowship', 'National Science Foundation', 'scholarship', 'Prestigious three-year fellowship for STEM grad students. $37,000 annual stipend plus $12,000 cost-of-education allowance for research-based degrees.', '2025-04-30', '2025-02-15', '2025-04-30', 'https://www.nsfgrfp.org', ARRAY['US citizen or permanent resident', 'Graduate student in STEM', 'Strong research potential', 'Academic excellence']),
